18	type CitationWithVisibility = PublicCitation & {
19	  conclusion_title?: string | null;
20	  conclusionTitle?: string | null;
21	  source_visibility?: string | null;
22	  visibility?: string | null;
23	  source_standing?: string | null;
24	  sourceStanding?: string | null;
25	  standing_reason?: string | null;
26	  standingReason?: string | null;
27	};
