30	  | "active"
31	  | "retracted"
32	  | "corrected"
33	  | "disputed"
34	  | "expired";
35	
36	const STANDING_STYLE: Record<Exclude<SourceStanding, "active">, { bg: string; fg: string; label: string }> = {
37	  retracted: { bg: "#5b1414", fg: "#ffd1d1", label: "Retracted" },
38	  corrected: { bg: "#5b3414", fg: "#ffe2c2", label: "Corrected" },
