58	interface CitationPopoverProps {
59	  open: boolean;
60	  onClose: () => void;
61	  anchorRef: RefObject<HTMLElement | null>;
62	  citation: CitationWithVisibility;
63	  conclusionText: string;
64	  publicUrl: string | null;
65	  id?: string;
66	}
67	
68	interface PopoverPosition {
69	  left: number;
70	  top: number;
71	}
72	
73	const FOCUSABLE_SELECTOR =
74	  'a[href], button:not([disabled]), textarea:not([disabled]), input:not([disabled]), select:not([disabled]), [tabindex]:not([tabindex="-1"])';
75	const ESTIMATED_HEIGHT = 250;
76	const MARGIN = 12;
77	const WIDTH = 360;
78	const POPOVER_Z_INDEX = 10020;
79	
80	const shellStyle: CSSProperties = {
81	  background: "var(--currents-bg-elevated)",
82	  border: "1px solid var(--currents-border)",
83	  borderRadius: "6px",
84	  boxShadow: "0 18px 45px rgba(0, 0, 0, 0.38)",
85	  color: "var(--currents-parchment)",
86	  maxWidth: `calc(100vw - ${MARGIN * 2}px)`,
87	  padding: "0.85rem",
88	  position: "fixed",
89	  width: `${WIDTH}px`,
90	  zIndex: POPOVER_Z_INDEX,
91	};
92	
93	const captionStyle: CSSProperties = {
94	  color: "var(--currents-muted)",
95	  fontFamily: "'IBM Plex Mono', monospace",
96	  fontSize: "0.68rem",
97	  letterSpacing: "0.12em",
98	  textTransform: "uppercase",
99	};
100	
101	const titleStyle: CSSProperties = {
102	  color: "var(--currents-parchment)",
103	  fontFamily: "'EB Garamond', serif",
104	  fontSize: "1rem",
105	  lineHeight: 1.25,
106	  margin: "0.25rem 0 0",
107	};
108	
109	const bodyStyle: CSSProperties = {
110	  color: "var(--currents-parchment-dim)",
111	  fontSize: "0.9rem",
112	  lineHeight: 1.55,
113	  marginTop: "0.65rem",
114	  maxHeight: "16rem",
115	  overflow: "auto",
116	};
117	
118	const linkStyle: CSSProperties = {
119	  color: "var(--currents-gold)",
120	  display: "inline-flex",
121	  fontSize: "0.84rem",
122	  marginTop: "0.7rem",
123	  textDecoration: "none",
124	};
125	
126	const privateNoteStyle: CSSProperties = {
127	  borderTop: "1px solid var(--currents-border)",
128	  color: "var(--currents-muted)",
129	  fontSize: "0.78rem",
130	  lineHeight: 1.45,
131	  margin: "0.75rem 0 0",
132	  paddingTop: "0.6rem",
133	};
134	
135	function citationKind(citation: PublicCitation): string {
136	  const kind = citation.source_kind.trim().toLowerCase();
137	  if (kind === "claim") return "opinion";
138	  if (kind === "conclusion") return "firm conclusion";
139	  return kind || "firm source";
140	}
141	
142	function citationTitle(citation: CitationWithVisibility): string {
143	  return (
144	    citation.conclusion_title?.trim() ||
145	    citation.conclusionTitle?.trim() ||
146	    citationKind(citation)
147	  );
148	}
149	
150	function normalizedVisibility(citation: CitationWithVisibility): string {
151	  return (citation.source_visibility ?? citation.visibility ?? "")
152	    .trim()
153	    .toLowerCase()
154	    .replace(/-/g, "_");
155	}
156	
157	function canExposePublicUrl(citation: CitationWithVisibility, publicUrl: string | null): boolean {
158	  return Boolean(publicUrl?.trim()) && normalizedVisibility(citation) === "org";
159	}
160	
161	function safeHref(rawUrl: string | null): string | null {
162	  const trimmed = rawUrl?.trim();
163	  if (!trimmed) return null;
164	  if (trimmed.startsWith("/") && !trimmed.startsWith("//")) return trimmed;
165	  try {
166	    const url = new URL(trimmed);
167	    if (url.protocol === "http:" || url.protocol === "https:") return url.toString();
168	  } catch {
169	    return null;
170	  }
171	  return null;
172	}
173	
174	function isHTMLElement(value: unknown): value is HTMLElement {
175	  if (!value || typeof value !== "object") return false;
176	  if (typeof HTMLElement === "undefined") {
177	    return typeof (value as HTMLElement).focus === "function";
178	  }
179	  return value instanceof HTMLElement;
180	}
181	
182	function focusableElements(container: HTMLElement): HTMLElement[] {
183	  return Array.from(container.querySelectorAll<HTMLElement>(FOCUSABLE_SELECTOR)).filter(
184	    (element) => !element.hasAttribute("disabled") && element.tabIndex !== -1,
185	  );
186	}
187	
188	function anchorIsOutsideViewport(anchor: HTMLElement): boolean {
189	  const rect = anchor.getBoundingClientRect();
190	  const viewportWidth =
191	    window.innerWidth || document.documentElement?.clientWidth || WIDTH;
192	  const viewportHeight =
193	    window.innerHeight || document.documentElement?.clientHeight || ESTIMATED_HEIGHT;
194	  return (
195	    rect.bottom < 0 ||
196	    rect.top > viewportHeight ||
197	    rect.right < 0 ||
198	    rect.left > viewportWidth
199	  );
200	}
201	
202	function positionFor(anchor: HTMLElement, dialog: HTMLElement | null): PopoverPosition {
203	  const rect = anchor.getBoundingClientRect();
204	  const viewportWidth =
205	    window.innerWidth || document.documentElement?.clientWidth || WIDTH + MARGIN * 2;
206	  const viewportHeight =
207	    window.innerHeight || document.documentElement?.clientHeight || ESTIMATED_HEIGHT;
208	  const height = dialog?.offsetHeight || ESTIMATED_HEIGHT;
209	  const preferredTop = rect.top - height - 10;
210	  const top =
211	    preferredTop >= MARGIN
212	      ? preferredTop
213	      : Math.min(rect.bottom + 10, Math.max(MARGIN, viewportHeight - height - MARGIN));
214	  const centeredLeft = rect.left + rect.width / 2 - WIDTH / 2;
215	  const left = Math.min(
216	    Math.max(MARGIN, centeredLeft),
217	    Math.max(MARGIN, viewportWidth - WIDTH - MARGIN),
218	  );
219	  return { left, top };
220	}
221	
222	export default function CitationPopover({
223	  open,
224	  onClose,
225	  anchorRef,
226	  citation,
227	  conclusionText,
228	  publicUrl,
229	  id,
230	}: CitationPopoverProps) {
231	  const rawId = useId();
232	  const popoverId = id ?? `citation-popover-${rawId.replace(/:/g, "")}`;
233	  const dialogRef = useRef<HTMLDivElement | null>(null);
234	  const [position, setPosition] = useState<PopoverPosition | null>(null);
235	  const href = canExposePublicUrl(citation, publicUrl) ? safeHref(publicUrl) : null;
236	  const text =
237	    conclusionText.trim() ||
238	    citation.quoted_span.trim() ||
239	    "Firm conclusion text unavailable.";
240	
241	  const updatePosition = useCallback(() => {
242	    const anchor = anchorRef.current;
243	    if (!anchor) {
244	      onClose();
245	      return;
246	    }
247	    if (anchorIsOutsideViewport(anchor)) {
248	      onClose();
249	      return;
250	    }
251	    setPosition(positionFor(anchor, dialogRef.current));
252	  }, [anchorRef, onClose]);
253	
254	  useEffect(() => {
255	    if (!open) return;
256	    updatePosition();
257	    window.addEventListener("resize", updatePosition);
258	    window.addEventListener("scroll", updatePosition, true);
259	    return () => {
260	      window.removeEventListener("resize", updatePosition);
261	      window.removeEventListener("scroll", updatePosition, true);
262	    };
263	  }, [open, updatePosition]);
264	
265	  useEffect(() => {
266	    if (!open) return;
267	
268	    const handlePointerDown = (event: MouseEvent | TouchEvent) => {
269	      const target = event.target as Node | null;
270	      if (!target) return;
271	      if (dialogRef.current?.contains(target)) return;
272	      if (anchorRef.current?.contains(target)) return;
273	      onClose();
274	    };
275	
276	    const handleKeyDown = (event: KeyboardEvent) => {
277	      if (event.key === "Escape") {
278	        event.preventDefault();
279	        onClose();
280	      }
281	    };
282	
283	    document.addEventListener("mousedown", handlePointerDown);
284	    document.addEventListener("touchstart", handlePointerDown);
285	    document.addEventListener("keydown", handleKeyDown);
286	    return () => {
287	      document.removeEventListener("mousedown", handlePointerDown);
288	      document.removeEventListener("touchstart", handlePointerDown);
289	      document.removeEventListener("keydown", handleKeyDown);
290	    };
291	  }, [anchorRef, onClose, open]);
292	
293	  useEffect(() => {
294	    if (!open) return;
295	    const previousFocus = document.activeElement;
296	    const frame = window.requestAnimationFrame(() => {
297	      const dialog = dialogRef.current;
298	      if (!dialog) return;
299	      const [first] = focusableElements(dialog);
300	      (first ?? dialog).focus();
301	    });
302	
303	    return () => {
304	      window.cancelAnimationFrame(frame);
305	      if (isHTMLElement(previousFocus)) previousFocus.focus();
306	    };
307	  }, [open]);
308	
309	  const trapFocus = (event: ReactKeyboardEvent<HTMLDivElement>) => {
310	    if (event.key !== "Tab") return;
311	    const dialog = dialogRef.current;
312	    if (!dialog) return;
313	    const focusable = focusableElements(dialog);
314	    if (!focusable.length) {
315	      event.preventDefault();
316	      dialog.focus();
317	      return;
318	    }
319	
320	    const first = focusable[0];
321	    const last = focusable[focusable.length - 1];
322	    const active = document.activeElement;
323	    if (event.shiftKey && active === first) {
324	      event.preventDefault();
325	      last.focus();
326	    } else if (!event.shiftKey && active === last) {
327	      event.preventDefault();
328	      first.focus();
329	    }
330	  };
331	
332	  if (!open || typeof document === "undefined") return null;
333	
334	  const standing = normalizedStanding(citation);
335	  const standingMeta = standing === "active" ? null : STANDING_STYLE[standing];
336	  const reason = standingReason(citation);
337	
338	  return createPortal(
339	    <div
340	      aria-modal="false"
341	      id={popoverId}
342	      onKeyDown={trapFocus}
343	      ref={dialogRef}
344	      role="dialog"
345	      style={{
346	        ...shellStyle,
347	        left: `${position?.left ?? MARGIN}px`,
348	        opacity: position ? 1 : 0,
349	        top: `${position?.top ?? MARGIN}px`,
350	      }}
351	      tabIndex={-1}
352	    >
353	      <div
354	        style={{
355	          alignItems: "start",
356	          display: "flex",
357	          gap: "0.75rem",
358	          justifyContent: "space-between",
359	        }}
360	      >
361	        <div>
362	          <div style={captionStyle}>{citationKind(citation)}</div>
363	          <h2 style={titleStyle}>{citationTitle(citation)}</h2>
364	          {standingMeta ? (
365	            <div style={{ marginTop: "0.4rem" }}>
366	              <span
367	                aria-label={`Source standing: ${standingMeta.label}`}
368	                data-testid="source-standing-pill"
369	                style={{
370	                  background: standingMeta.bg,
371	                  border: "1px solid rgba(0,0,0,0.35)",
372	                  borderRadius: "999px",
373	                  color: standingMeta.fg,
374	                  display: "inline-block",
375	                  fontFamily: "'IBM Plex Mono', monospace",
376	                  fontSize: "0.65rem",
377	                  letterSpacing: "0.1em",
378	                  padding: "0.15rem 0.55rem",
379	                  textTransform: "uppercase",
380	                }}
381	              >
382	                {standingMeta.label}
383	              </span>
384	              {reason ? (
385	                <span
386	                  style={{
387	                    color: "var(--currents-muted)",
388	                    fontSize: "0.72rem",
389	                    marginLeft: "0.55rem",
390	                  }}
391	                >
392	                  {reason}
393	                </span>
394	              ) : null}
395	              {standing === "retracted" || standing === "corrected" ? (
396	                <a
397	                  href="/methodology#source-standing"
398	                  style={{
399	                    color: "var(--currents-gold)",
400	                    display: "inline-block",
401	                    fontSize: "0.72rem",
402	                    marginLeft: "0.55rem",
403	                    textDecoration: "underline",
404	                  }}
405	                >
406	                  this source has been retracted →
407	                </a>
408	              ) : null}
409	            </div>
410	          ) : null}
411	        </div>
412	        <button
413	          aria-label="Close citation"
414	          onClick={onClose}
415	          style={{
416	            background: "transparent",
417	            border: "1px solid var(--currents-border)",
418	            borderRadius: "4px",
419	            color: "var(--currents-parchment-dim)",
420	            cursor: "pointer",
421	            fontSize: "0.8rem",
422	            lineHeight: 1,
423	            padding: "0.25rem 0.35rem",
424	          }}
425	          type="button"
426	        >
427	          ×
428	        </button>
429	      </div>
430	
431	      <div style={bodyStyle}>{renderSafeMarkdown(text)}</div>
432	
433	      {href ? (
434	        <a href={href} rel="noopener nofollow ugc" style={linkStyle} target="_blank">
435	          Open the public conclusion →
436	        </a>
437	      ) : (
438	        <p style={privateNoteStyle}>
439	          Source recorded by the firm; not publicly available.
440	        </p>
441	      )}
442	    </div>,
443	    document.body,
444	  );
445	}
446

